import React, { useState, useEffect } from 'react';
import Helmet from 'react-helmet';
import L from 'leaflet';
import CovidDashboard from 'components/CovidDashboard';
import ShowGlobal from 'components/ShowGlobal';
//import { Marker } from 'react-leaflet';
import axios from 'axios';


//import { promiseToFlyTo, getCurrentLocation } from 'lib/map';
import Layout from 'components/Layout';
import Container from 'components/Container';
import Map from 'components/Map';

const LOCATION = {
  lat: 0,
  lng: 0,
};
const CENTER = [LOCATION.lat, LOCATION.lng];
const DEFAULT_ZOOM = 2;

const IndexPage = () => {
  /**
   * mapEffect
   * @description Fires a callback once the page renders
   * @example Here this is and example of being used to zoom in and set a popup on load
   */
  const [States, setStates] = useState([]);
  const [StatesCase, setStateCase] = useState([]);
  const [StatesDeath, setStateDeath] = useState([]);
  const [StatesTest, setStateTest] = useState([]);
  const [selectedState, setSelectedState] = useState(null);
  const [Global, setGlobal] = useState();
  const [GlobalCase, setGlobalCase] = useState();
  const [GlobalDeath, setGlobalDeath] = useState();





  useEffect(() => {
    const fetchData = async () => {
      try {
        const response = await axios.get('https://disease.sh/v3/covid-19/states');
        
        const { data } = response;

        const newArray = data.map(state => `${state.state}`);
        const newnewArray = data.map(state => `${state.cases.toLocaleString()}`);
        const newnewnewArray = data.map(state => `${state.deaths.toLocaleString()}`);
        const newnewnewnewArray = data.map(state => `${state.active.toLocaleString()}`);

    


        setStates(newArray);
        setStateCase(newnewArray);
        setStateDeath(newnewnewArray);
        setStateTest(newnewnewnewArray);

  
      } catch (error) {
        console.error('Error fetching data: ', error);
      }
    };

    fetchData(); 
  }, []); 

  useEffect(() => {
    const fetchData = async () => {
      try {
       const responseGlobal = await axios.get('https://disease.sh/v3/covid-19/all');
        
       const dataGlobal = responseGlobal.data; // Access 'data' directly

       // Extract desired properties
       const {
         cases,
         deaths,
        // todayCases,
         //todayDeaths,
         recovered,
         //active,
         //critical,
         //tests,
         //population,
       } = dataGlobal;



    
       setGlobalCase(cases.toLocaleString());
       setGlobalDeath(deaths.toLocaleString());
       setGlobal(recovered.toLocaleString());

      } catch (error) {
        console.error('Error fetching data: ', error);
      }
    };

    fetchData(); 
  }, []); 

  const handleStateChange = (selectedStateIndex) => {
    setSelectedState(selectedStateIndex);
  };
  async function mapEffect({ leafletElement: map } = {}) {
    if ( !map ) return;
    // Attempt to fetch data
    let response;
    try {
      response = await axios.get( 'https://disease.sh/v3/covid-19/countries' );
      console.log( 'Response: ', response );
    } catch ( e ) {
      console.error( 'Error fetching data: ', e );
    }

    // Destructure data
    const { data } = response;
    const hasData = Array.isArray( data ) && data.length > 0;
    // If there is no data (error), return
    if ( !hasData ) return;
    if (hasData) {
      // Access information for each country
      data.forEach(country => {
        const countryName = country.country;
        const cases = country.cases;

    //    console.log(`${countryName}: Cases - ${cases}`);
        // You can access other properties like deaths, recovered, etc. in a similar way
      });
    }
    // Transform data to GeoJSON
    const geoJSON = {
      type: 'FeatureCollection',
      features: data.map(( country = {}) => {
        const { countryInfo = {} } = country;
        const { lat, long: lng } = countryInfo;

        return {
          type: 'Feature',
          properties: {
            ...country,
          },
          geometry: {
            type: 'Point',
            coordinates: [lng, lat],
          },
        };
      }),
    };
    
    function countryPointToLayer( feature = {}, latlng ) {
      const { properties = {} } = feature;
      let updateFormatted;
      let caseString;

      // destructure data
      const { country, updated, cases, deaths, recovered } = properties;

      caseString = `${cases}`;

      if ( cases > 1000 ) {
        caseString = `${caseString.slice( 0, -3 )}k+`;
      }

      if ( updated ) {
        updateFormatted = new Date( updated ).toLocaleString();
      }

      const html = `
<span class="icon-marker">
    <span class="icon-marker-tooltip">
        <h2>${country}</h2>
        <ul>
            <li><strong>Confirmed: </strong>${cases}</li>
            <li><strong>Deaths: </strong>${deaths}</li>
            <li><strong>Recovered: </strong>${recovered}</li>
            <li><strong>Last Update: </strong>${updateFormatted}</li>
        </ul>
    </span>
    ${caseString}
</span>
`;
      return L.marker( latlng, {
        icon: L.divIcon({
          className: 'icon',
          html,
        }),
        riseOnHover: true,
      });
    }

    // Insert GeoJSON into map
    const geoJSONLayers = new L.GeoJSON( geoJSON, {
      pointToLayer: countryPointToLayer,
    });
    geoJSONLayers.addTo( map );
  }

  const mapSettings = {
    center: CENTER,
    defaultBaseMap: 'MapBox',
    zoom: DEFAULT_ZOOM,
    mapEffect,
  };

    const containerStyle = {
      display: 'flex',
      flexDirection: 'column',
      alignItems: 'center',
      justifyContent: 'space-between',
     
    };
  
  const centeredContentStyle = {
    display: 'flex',
    flexDirection: 'column',
    alignItems: 'center',  
    padding: '10px',
    size: '100'
    //marginTop: '20px',
  };
  return (
    <Layout pageName="home">
      <Helmet>
        <title>Home Page</title>
      </Helmet>

      <Map {...mapSettings} />

  <ShowGlobal
   globalCase={GlobalCase}
   globalName={Global}
   globalDeath={GlobalDeath}/>
   <br></br><br></br><br></br>
  
   <div style={containerStyle}>
  <label>Select a state:</label>
  <select onChange={(e) => handleStateChange(e.target.value)}>
    <option value={null}>-- Select a state --</option>
    {States.map((state, index) => (
      <option key={index} value={index}>
        {state}
      </option>
    ))}
  </select>

  {selectedState !== null && (
    <div style={centeredContentStyle}>
      <CovidDashboard 
        stateCase={[StatesCase[selectedState]]}
        stateName={[States[selectedState]]}
        stateDeath={[StatesDeath[selectedState]]}
        stateTest={[StatesTest[selectedState]]}

      />
    </div>
  )}
</div>


      <Container type="content" className="text-center home-start">
        <h2>Still Getting Started?</h2>
        <p>Run the following in your terminal!</p>
        <pre>
          <code>gatsby new [directory] https://github.com/colbyfayock/gatsby-starter-leaflet</code>
        </pre>
        <p className="note">Note: Gatsby CLI required globally for the above command</p>
      </Container>
    </Layout>
  );
};

export default IndexPage;