import React from 'react';

const CovidDashboard = ({ stateCase, stateName, stateDeath ,stateTest}) => {
  const containerStyle = {
    borderTop: 'solid 1px blue',
    borderBottom: 'solid 1px blue',
 
    paddingTop: '30px'
  };

  const roundedAndThreeDBorderStyle = {
    borderRadius: '10px', // Adjust the border radius as needed
    border: '1px solid #ccc',
    padding: '8px',
    margin: '4px',
    boxShadow: '0 0 5px rgba(0, 0, 0, 0.1)', // Adjust the shadow as needed
  };
  const listItemStyle = {
    background: '#3d3c48',
    border: '1px solid #ccc',
    ...roundedAndThreeDBorderStyle,
    padding: '20px',
    margin: '4px',
    display: 'flex',
    flexDirection: 'column',
    alignItems: "center",
    color: 'white',
    fontFamily: 'Arial, sans-serif', // Change the font family as needed
    fontSize: '16px',
  };

  
  
  
  return (
    <div style={containerStyle}>
      <ul style={{ display: 'flex', flexWrap: 'wrap', padding: 0, margin: 0 }}>
        {stateName.map((item, index) => (
          <li key={index} style={listItemStyle}>
            {item}
            <br></br>
            <strong>Total Cases: {stateCase[index]}</strong>
            <strong>Total Tests: {stateTest[index]}</strong>
            <strong>Total Deaths: {stateDeath[index]}</strong>
          </li>
        ))}
      </ul>
    </div>
  );
};

export default CovidDashboard;
